// ============================ AddressNativeState =============================
class AddressNativeState : public jsi::NativeState {
public:
  explicit AddressNativeState(RPtr ptr) : ptr_(ptr) {}
  ~AddressNativeState() { if (ptr_._0) csl_bridge_rptr_free(&ptr_); }
  [[nodiscard]] RPtr get() const { return ptr_; }
private:
  RPtr ptr_{nullptr};
};

static std::shared_ptr<AddressNativeState> getAddressState(
    jsi::Runtime& rt, const jsi::Object& val, const char* argName) {
  if (!val.hasNativeState<AddressNativeState>(rt)) {
    throw jsi::JSError(rt, std::string("Expected Address for ") + argName);
  }
  return val.getNativeState<AddressNativeState>(rt);
}

static std::shared_ptr<AddressNativeState> getThisAddressState(jsi::Runtime& rt, const jsi::Value& thisVal) {
  if (!thisVal.isObject()) throw jsi::JSError(rt, "Address method: 'this' is not an object");
  return getAddressState(rt, thisVal.asObject(rt), "this");
}

