// ===================== Address ========================
static std::optional<jsi::WeakObject> s_Address_proto_weak;

static jsi::Object getOrCreateAddressProto(jsi::Runtime& rt);

// ---------- Wrappers to create Address and attach prototype --------------
static jsi::Object createAddressRaw(jsi::Runtime& rt, const RPtr& ptr) {
  jsi::Object obj(rt);
  obj.setNativeState(rt, std::make_shared<AddressNativeState>(ptr));
  return obj;
}

static jsi::Object makeAddressInstance(jsi::Runtime& rt, const RPtr& ptr) {
  jsi::Object obj = createAddressRaw(rt, ptr);
  jsi::Object proto = getOrCreateAddressProto(rt);
  setPrototype(rt, obj, proto);
  return obj;
}

static jsi::Object callCslAddress(jsi::Runtime& rt, std::function<bool(RPtr*, CharPtr*)> fn, const char* location) {
  RPtr result{nullptr};
  ScopedCharPtr err;
  if (!fn(&result, &err.ptr)) {
    std::string errorMsg = err.ptr ? err.ptr : (std::string(location) + ": Unknown CSL error");
    throw jsi::JSError(rt, errorMsg);
  }
  return makeAddressInstance(rt, result);
}

static jsi::Object getOrCreateAddressProto(jsi::Runtime& rt) {
  if (s_Address_proto_weak.has_value()) {
    auto locked = s_Address_proto_weak->lock(rt);
    if (locked.isObject()) {
      return locked.asObject(rt);
    }
  }

  jsi::Object proto(rt);

  // to_json(): String
  proto.setProperty(rt, "to_json",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "to_json"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisAddressState(rt, thisVal);
        return callCslString(rt, [&](CharPtr* out, CharPtr* err) {
          return csl_bridge_address_to_json(st->get(), out, err);
        }, "Address.to_json");
      }
    )
  );

  // kind(): AddressKind
  proto.setProperty(rt, "kind",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "kind"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisAddressState(rt, thisVal);
        int32_t res{}; ScopedCharPtr err;
        if (!csl_bridge_address_kind(st->get(), &res, &err.ptr)) {
          throw jsi::JSError(rt, err.ptr ? err.ptr : "Address.kind: Unknown CSL error");
        }
        return jsi::Value(static_cast<double>(res));
      }
    )
  );

  // payment_cred(): Credential
  proto.setProperty(rt, "payment_cred",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "payment_cred"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisAddressState(rt, thisVal);
        return callCslCredential(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_address_payment_cred(st->get(), out, err);
        }, "Address.payment_cred");
      }
    )
  );

  // is_malformed(): boolean
  proto.setProperty(rt, "is_malformed",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "is_malformed"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisAddressState(rt, thisVal);
        bool res = false; ScopedCharPtr err;
        if (!csl_bridge_address_is_malformed(st->get(), &res, &err.ptr)) {
          throw jsi::JSError(rt, err.ptr ? err.ptr : "Address.is_malformed: Unknown CSL error");
        }
        return jsi::Value(res);
      }
    )
  );

  // to_hex(): String
  proto.setProperty(rt, "to_hex",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "to_hex"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisAddressState(rt, thisVal);
        return callCslString(rt, [&](CharPtr* out, CharPtr* err) {
          return csl_bridge_address_to_hex(st->get(), out, err);
        }, "Address.to_hex");
      }
    )
  );

  // to_bytes(): Uint8Array
  proto.setProperty(rt, "to_bytes",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "to_bytes"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisAddressState(rt, thisVal);
        return callCslArray(rt, [&](DataPtr* out, CharPtr* err) {
          return csl_bridge_address_to_bytes(st->get(), out, err);
        }, "Address.to_bytes");
      }
    )
  );

  // to_bech32(): String
  proto.setProperty(rt, "to_bech32",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "to_bech32"), 1,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisAddressState(rt, thisVal);
        std::string prefix;
        bool has_prefix = false;
        if (count >= 1 && !args[0].isUndefined() && !args[0].isNull()) {
          if (!args[0].isString()) {
            throw jsi::JSError(rt, "Address.to_bech32(prefix): expected string");
          }
          prefix = args[0].asString(rt).utf8(rt);
          has_prefix = true;
        }
        if (has_prefix) {
          return callCslString(rt, [&](CharPtr* out, CharPtr* err) {
            return csl_bridge_address_to_bech32_with_prefix(st->get(), prefix.c_str(), out, err);
          }, "Address.to_bech32");
        } else {
          return callCslString(rt, [&](CharPtr* out, CharPtr* err) {
            return csl_bridge_address_to_bech32(st->get(), out, err);
          }, "Address.to_bech32");
        }
      }
    )
  );

  // network_id(): number
  proto.setProperty(rt, "network_id",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "network_id"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisAddressState(rt, thisVal);
        int64_t res{}; ScopedCharPtr err;
        if (!csl_bridge_address_network_id(st->get(), &res, &err.ptr)) {
          throw jsi::JSError(rt, err.ptr ? err.ptr : "Address.network_id: Unknown CSL error");
        }
        return jsi::Value(static_cast<double>(res));
      }
    )
  );

  // Freeze the prototype, to prevent JS from changing methods accidentally
  auto ObjectCtor = rt.global().getPropertyAsObject(rt, "Object");
  if (ObjectCtor.isFunction(rt)) {
    auto freezeVal = ObjectCtor.getProperty(rt, "freeze");
    if (freezeVal.isObject() && freezeVal.asObject(rt).isFunction(rt)) {
      freezeVal.asObject(rt).asFunction(rt).call(rt, proto);
    }
  }

  s_Address_proto_weak = jsi::WeakObject(rt, proto);
  return proto;
}

static jsi::Object makeAddressExport(jsi::Runtime& rt) {
  jsi::Object ns(rt);

  // from_bytes
  ns.setProperty(rt, "from_bytes",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "from_bytes"), 1,
      [](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t count) -> jsi::Value {
        if (count < 1 || !args[0].isObject()) {
          throw jsi::JSError(rt, "Address.from_bytes(data): expected Uint8Array");
        }
        auto data = parseUint8Array(rt, args[0].asObject(rt), "Address.from_bytes", "data");
        return callCslAddress(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_address_from_bytes(data.data(), static_cast<size_t>(data.size()), out, err);
        }, "Address.from_bytes");
      }
    )
  );

  // from_json
  ns.setProperty(rt, "from_json",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "from_json"), 1,
      [](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t count) -> jsi::Value {
        if (count < 1 || !args[0].isString()) {
          throw jsi::JSError(rt, "Address.from_json(json): expected string");
        }
        std::string json = args[0].asString(rt).utf8(rt);
        return callCslAddress(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_address_from_json(json.c_str(), out, err);
        }, "Address.from_json");
      }
    )
  );

  // from_hex
  ns.setProperty(rt, "from_hex",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "from_hex"), 1,
      [](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t count) -> jsi::Value {
        if (count < 1 || !args[0].isString()) {
          throw jsi::JSError(rt, "Address.from_hex(hex_str): expected string");
        }
        std::string hex_str = args[0].asString(rt).utf8(rt);
        return callCslAddress(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_address_from_hex(hex_str.c_str(), out, err);
        }, "Address.from_hex");
      }
    )
  );

  // from_bech32
  ns.setProperty(rt, "from_bech32",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "from_bech32"), 1,
      [](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t count) -> jsi::Value {
        if (count < 1 || !args[0].isString()) {
          throw jsi::JSError(rt, "Address.from_bech32(bech_str): expected string");
        }
        std::string bech_str = args[0].asString(rt).utf8(rt);
        return callCslAddress(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_address_from_bech32(bech_str.c_str(), out, err);
        }, "Address.from_bech32");
      }
    )
  );

  auto ObjectCtor = rt.global().getPropertyAsObject(rt, "Object");
  if (ObjectCtor.isFunction(rt)) {
    auto freezeVal = ObjectCtor.getProperty(rt, "freeze");
    if (freezeVal.isObject() && freezeVal.asObject(rt).isFunction(rt)) {
      freezeVal.asObject(rt).asFunction(rt).call(rt, ns);
    }
  }

  return ns;
}

