// ===================== Certificates ========================
static std::optional<jsi::WeakObject> s_Certificates_proto_weak;

static jsi::Object getOrCreateCertificatesProto(jsi::Runtime& rt);

// ---------- Wrappers to create Certificates and attach prototype --------------
static jsi::Object createCertificatesRaw(jsi::Runtime& rt, const RPtr& ptr) {
  jsi::Object obj(rt);
  obj.setNativeState(rt, std::make_shared<CertificatesNativeState>(ptr));
  return obj;
}

static jsi::Object makeCertificatesInstance(jsi::Runtime& rt, const RPtr& ptr) {
  jsi::Object obj = createCertificatesRaw(rt, ptr);
  jsi::Object proto = getOrCreateCertificatesProto(rt);
  setPrototype(rt, obj, proto);
  return obj;
}

static jsi::Object callCslCertificates(jsi::Runtime& rt, std::function<bool(RPtr*, CharPtr*)> fn, const char* location) {
  RPtr result{nullptr};
  ScopedCharPtr err;
  if (!fn(&result, &err.ptr)) {
    std::string errorMsg = err.ptr ? err.ptr : (std::string(location) + ": Unknown CSL error");
    throw jsi::JSError(rt, errorMsg);
  }
  return makeCertificatesInstance(rt, result);
}

static jsi::Object getOrCreateCertificatesProto(jsi::Runtime& rt) {
  if (s_Certificates_proto_weak.has_value()) {
    auto locked = s_Certificates_proto_weak->lock(rt);
    if (locked.isObject()) {
      return locked.asObject(rt);
    }
  }

  jsi::Object proto(rt);

  // to_bytes(): Uint8Array
  proto.setProperty(rt, "to_bytes",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "to_bytes"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisCertificatesState(rt, thisVal);
        return callCslArray(rt, [&](DataPtr* out, CharPtr* err) {
          return csl_bridge_certificates_to_bytes(st->get(), out, err);
        }, "Certificates.to_bytes");
      }
    )
  );

  // to_hex(): String
  proto.setProperty(rt, "to_hex",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "to_hex"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisCertificatesState(rt, thisVal);
        return callCslString(rt, [&](CharPtr* out, CharPtr* err) {
          return csl_bridge_certificates_to_hex(st->get(), out, err);
        }, "Certificates.to_hex");
      }
    )
  );

  // to_json(): String
  proto.setProperty(rt, "to_json",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "to_json"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisCertificatesState(rt, thisVal);
        return callCslString(rt, [&](CharPtr* out, CharPtr* err) {
          return csl_bridge_certificates_to_json(st->get(), out, err);
        }, "Certificates.to_json");
      }
    )
  );

  // len(): number
  proto.setProperty(rt, "len",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "len"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisCertificatesState(rt, thisVal);
        int64_t res{}; ScopedCharPtr err;
        if (!csl_bridge_certificates_len(st->get(), &res, &err.ptr)) {
          throw jsi::JSError(rt, err.ptr ? err.ptr : "Certificates.len: Unknown CSL error");
        }
        return jsi::Value(static_cast<double>(res));
      }
    )
  );

  // get(): Certificate
  proto.setProperty(rt, "get",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "get"), 1,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisCertificatesState(rt, thisVal);
        if (count < 1 || !args[0].isNumber()) {
          throw jsi::JSError(rt, "Certificates.get(index): expected number");
        }
        auto index = static_cast<int64_t>(args[0].asNumber());
        RPtr result{nullptr};
        ScopedCharPtr err;
        if (!csl_bridge_certificates_get(st->get(), index, &result, &err.ptr)) {
          if (!err.ptr) {
            return jsi::Value::null();
          }
          throw jsi::JSError(rt, err.ptr ? err.ptr : "Certificates.get: Unknown CSL error");
        }
        if (result._0 == nullptr) {
          return jsi::Value::null();
        }
        return jsi::Value(callCslCertificate(rt, [&](RPtr* out, CharPtr* err) {
          *out = result;
          return true;
        }, "Certificates.get"));
      }
    )
  );

  // add(): boolean
  proto.setProperty(rt, "add",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "add"), 1,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisCertificatesState(rt, thisVal);
        if (count < 1 || !args[0].isObject()) {
          throw jsi::JSError(rt, "Certificates.add(elem): expected Certificate");
        }
        auto elem = getCertificateState(rt, args[0].asObject(rt), "elem");
        bool res = false; ScopedCharPtr err;
        if (!csl_bridge_certificates_add(st->get(), elem->get(), &res, &err.ptr)) {
          throw jsi::JSError(rt, err.ptr ? err.ptr : "Certificates.add: Unknown CSL error");
        }
        return jsi::Value(res);
      }
    )
  );

  // Freeze the prototype, to prevent JS from changing methods accidentally
  auto ObjectCtor = rt.global().getPropertyAsObject(rt, "Object");
  if (ObjectCtor.isFunction(rt)) {
    auto freezeVal = ObjectCtor.getProperty(rt, "freeze");
    if (freezeVal.isObject() && freezeVal.asObject(rt).isFunction(rt)) {
      freezeVal.asObject(rt).asFunction(rt).call(rt, proto);
    }
  }

  s_Certificates_proto_weak = jsi::WeakObject(rt, proto);
  return proto;
}

static jsi::Object makeCertificatesExport(jsi::Runtime& rt) {
  jsi::Object ns(rt);

  // from_bytes
  ns.setProperty(rt, "from_bytes",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "from_bytes"), 1,
      [](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t count) -> jsi::Value {
        if (count < 1 || !args[0].isObject()) {
          throw jsi::JSError(rt, "Certificates.from_bytes(bytes): expected Uint8Array");
        }
        auto bytes = parseUint8Array(rt, args[0].asObject(rt), "Certificates.from_bytes", "bytes");
        return callCslCertificates(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_certificates_from_bytes(bytes.data(), static_cast<size_t>(bytes.size()), out, err);
        }, "Certificates.from_bytes");
      }
    )
  );

  // from_hex
  ns.setProperty(rt, "from_hex",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "from_hex"), 1,
      [](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t count) -> jsi::Value {
        if (count < 1 || !args[0].isString()) {
          throw jsi::JSError(rt, "Certificates.from_hex(hex_str): expected string");
        }
        std::string hex_str = args[0].asString(rt).utf8(rt);
        return callCslCertificates(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_certificates_from_hex(hex_str.c_str(), out, err);
        }, "Certificates.from_hex");
      }
    )
  );

  // from_json
  ns.setProperty(rt, "from_json",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "from_json"), 1,
      [](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t count) -> jsi::Value {
        if (count < 1 || !args[0].isString()) {
          throw jsi::JSError(rt, "Certificates.from_json(json): expected string");
        }
        std::string json = args[0].asString(rt).utf8(rt);
        return callCslCertificates(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_certificates_from_json(json.c_str(), out, err);
        }, "Certificates.from_json");
      }
    )
  );

  // new
  ns.setProperty(rt, "new",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "new"), 0,
      [](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t count) -> jsi::Value {
        return callCslCertificates(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_certificates_new(out, err);
        }, "Certificates.new");
      }
    )
  );

  auto ObjectCtor = rt.global().getPropertyAsObject(rt, "Object");
  if (ObjectCtor.isFunction(rt)) {
    auto freezeVal = ObjectCtor.getProperty(rt, "freeze");
    if (freezeVal.isObject() && freezeVal.asObject(rt).isFunction(rt)) {
      freezeVal.asObject(rt).asFunction(rt).call(rt, ns);
    }
  }

  return ns;
}

