static std::optional<jsi::WeakObject> s_NativeScriptSource_proto_weak;

static jsi::Object getOrCreateNativeScriptSourceProto(jsi::Runtime& rt);

// ---------- Wrappers to create NativeScriptSource and attach prototype --------------
static jsi::Object createNativeScriptSourceRaw(jsi::Runtime& rt, const RPtr& ptr) {
  jsi::Object obj(rt);
  obj.setNativeState(rt, std::make_shared<NativeScriptSourceNativeState>(ptr));
  return obj;
}

static jsi::Object makeNativeScriptSourceInstance(jsi::Runtime& rt, const RPtr& ptr) {
  jsi::Object obj = createNativeScriptSourceRaw(rt, ptr);
  jsi::Object proto = getOrCreateNativeScriptSourceProto(rt);
  setPrototype(rt, obj, proto);
  return obj;
}

static jsi::Object callCslNativeScriptSource(jsi::Runtime& rt, std::function<bool(RPtr*, CharPtr*)> fn, const char* location) {
  RPtr result{nullptr};
  ScopedCharPtr err;
  if (!fn(&result, &err.ptr)) {
    std::string errorMsg = err.ptr ? err.ptr : (std::string(location) + ": Unknown CSL error");
    throw jsi::JSError(rt, errorMsg);
  }
  return makeNativeScriptSourceInstance(rt, result);
}

static jsi::Object getOrCreateNativeScriptSourceProto(jsi::Runtime& rt) {
  if (s_NativeScriptSource_proto_weak.has_value()) {
    auto locked = s_NativeScriptSource_proto_weak->lock(rt);
    if (locked.isObject()) {
      return locked.asObject(rt);
    }
  }

  jsi::Object proto(rt);

  // set_required_signers(): void
  proto.setProperty(rt, "set_required_signers",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "set_required_signers"), 1,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisNativeScriptSourceState(rt, thisVal);
        if (count < 1 || !args[0].isObject()) {
          throw jsi::JSError(rt, "NativeScriptSource.set_required_signers(key_hashes): expected Ed25519KeyHashes");
        }
        auto key_hashes = getEd25519KeyHashesState(rt, args[0].asObject(rt), "key_hashes");
        ScopedCharPtr err;
        if (!csl_bridge_native_script_source_set_required_signers(st->get(), key_hashes->get(), &err.ptr)) {
          throw jsi::JSError(rt, err.ptr ? err.ptr : "NativeScriptSource.set_required_signers: Unknown CSL error");
        }
        return jsi::Value::undefined();
      }
    )
  );

  // get_ref_script_size(): number
  proto.setProperty(rt, "get_ref_script_size",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "get_ref_script_size"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisNativeScriptSourceState(rt, thisVal);
        int64_t res{}; ScopedCharPtr err;
        if (!csl_bridge_native_script_source_get_ref_script_size(st->get(), &res, &err.ptr)) {
          throw jsi::JSError(rt, err.ptr ? err.ptr : "NativeScriptSource.get_ref_script_size: Unknown CSL error");
        }
        return jsi::Value(static_cast<double>(res));
      }
    )
  );

  // Freeze the prototype, to prevent JS from changing methods accidentally
  auto ObjectCtor = rt.global().getPropertyAsObject(rt, "Object");
  if (ObjectCtor.isFunction(rt)) {
    auto freezeVal = ObjectCtor.getProperty(rt, "freeze");
    if (freezeVal.isObject() && freezeVal.asObject(rt).isFunction(rt)) {
      freezeVal.asObject(rt).asFunction(rt).call(rt, proto);
    }
  }

  s_NativeScriptSource_proto_weak = jsi::WeakObject(rt, proto);
  return proto;
}

static jsi::Object makeNativeScriptSourceExport(jsi::Runtime& rt) {
  jsi::Object ns(rt);

  // new
  ns.setProperty(rt, "new",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "new"), 1,
      [](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t count) -> jsi::Value {
        if (count < 1 || !args[0].isObject()) {
          throw jsi::JSError(rt, "NativeScriptSource.new(script): expected NativeScript");
        }
        auto script = getNativeScriptState(rt, args[0].asObject(rt), "script");
        return callCslNativeScriptSource(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_native_script_source_new(script->get(), out, err);
        }, "NativeScriptSource.new");
      }
    )
  );

  // new_ref_input
  ns.setProperty(rt, "new_ref_input",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "new_ref_input"), 3,
      [](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t count) -> jsi::Value {
        if (count < 1 || !args[0].isObject()) {
          throw jsi::JSError(rt, "NativeScriptSource.new_ref_input(script_hash): expected ScriptHash");
        }
        auto script_hash = getScriptHashState(rt, args[0].asObject(rt), "script_hash");
        if (count < 2 || !args[1].isObject()) {
          throw jsi::JSError(rt, "NativeScriptSource.new_ref_input(input): expected TransactionInput");
        }
        auto input = getTransactionInputState(rt, args[1].asObject(rt), "input");
        if (count < 3 || !args[2].isNumber()) {
          throw jsi::JSError(rt, "NativeScriptSource.new_ref_input(script_size): expected number");
        }
        auto script_size = static_cast<int64_t>(args[2].asNumber());
        return callCslNativeScriptSource(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_native_script_source_new_ref_input(script_hash->get(), input->get(), script_size, out, err);
        }, "NativeScriptSource.new_ref_input");
      }
    )
  );

  auto ObjectCtor = rt.global().getPropertyAsObject(rt, "Object");
  if (ObjectCtor.isFunction(rt)) {
    auto freezeVal = ObjectCtor.getProperty(rt, "freeze");
    if (freezeVal.isObject() && freezeVal.asObject(rt).isFunction(rt)) {
      freezeVal.asObject(rt).asFunction(rt).call(rt, ns);
    }
  }

  return ns;
}

