static std::optional<jsi::WeakObject> s_PlutusList_proto_weak;

static jsi::Object getOrCreatePlutusListProto(jsi::Runtime& rt);

// ---------- Wrappers to create PlutusList and attach prototype --------------
static jsi::Object createPlutusListRaw(jsi::Runtime& rt, const RPtr& ptr) {
  jsi::Object obj(rt);
  obj.setNativeState(rt, std::make_shared<PlutusListNativeState>(ptr));
  return obj;
}

static jsi::Object makePlutusListInstance(jsi::Runtime& rt, const RPtr& ptr) {
  jsi::Object obj = createPlutusListRaw(rt, ptr);
  jsi::Object proto = getOrCreatePlutusListProto(rt);
  setPrototype(rt, obj, proto);
  return obj;
}

static jsi::Object callCslPlutusList(jsi::Runtime& rt, std::function<bool(RPtr*, CharPtr*)> fn, const char* location) {
  RPtr result{nullptr};
  ScopedCharPtr err;
  if (!fn(&result, &err.ptr)) {
    std::string errorMsg = err.ptr ? err.ptr : (std::string(location) + ": Unknown CSL error");
    throw jsi::JSError(rt, errorMsg);
  }
  return makePlutusListInstance(rt, result);
}

static jsi::Object getOrCreatePlutusListProto(jsi::Runtime& rt) {
  if (s_PlutusList_proto_weak.has_value()) {
    auto locked = s_PlutusList_proto_weak->lock(rt);
    if (locked.isObject()) {
      return locked.asObject(rt);
    }
  }

  jsi::Object proto(rt);

  // to_bytes(): Uint8Array
  proto.setProperty(rt, "to_bytes",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "to_bytes"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisPlutusListState(rt, thisVal);
        return callCslArray(rt, [&](DataPtr* out, CharPtr* err) {
          return csl_bridge_plutus_list_to_bytes(st->get(), out, err);
        }, "PlutusList.to_bytes");
      }
    )
  );

  // to_hex(): String
  proto.setProperty(rt, "to_hex",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "to_hex"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisPlutusListState(rt, thisVal);
        return callCslString(rt, [&](CharPtr* out, CharPtr* err) {
          return csl_bridge_plutus_list_to_hex(st->get(), out, err);
        }, "PlutusList.to_hex");
      }
    )
  );

  // len(): number
  proto.setProperty(rt, "len",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "len"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisPlutusListState(rt, thisVal);
        int64_t res{}; ScopedCharPtr err;
        if (!csl_bridge_plutus_list_len(st->get(), &res, &err.ptr)) {
          throw jsi::JSError(rt, err.ptr ? err.ptr : "PlutusList.len: Unknown CSL error");
        }
        return jsi::Value(static_cast<double>(res));
      }
    )
  );

  // get(): PlutusData
  proto.setProperty(rt, "get",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "get"), 1,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisPlutusListState(rt, thisVal);
        if (count < 1 || !args[0].isNumber()) {
          throw jsi::JSError(rt, "PlutusList.get(index): expected number");
        }
        auto index = static_cast<int64_t>(args[0].asNumber());
        RPtr result{nullptr};
        ScopedCharPtr err;
        if (!csl_bridge_plutus_list_get(st->get(), index, &result, &err.ptr)) {
          if (!err.ptr) {
            return jsi::Value::null();
          }
          throw jsi::JSError(rt, err.ptr ? err.ptr : "PlutusList.get: Unknown CSL error");
        }
        if (result._0 == nullptr) {
          return jsi::Value::null();
        }
        return jsi::Value(callCslPlutusData(rt, [&](RPtr* out, CharPtr* err) {
          *out = result;
          return true;
        }, "PlutusList.get"));
      }
    )
  );

  // add(): void
  proto.setProperty(rt, "add",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "add"), 1,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisPlutusListState(rt, thisVal);
        if (count < 1 || !args[0].isObject()) {
          throw jsi::JSError(rt, "PlutusList.add(elem): expected PlutusData");
        }
        auto elem = getPlutusDataState(rt, args[0].asObject(rt), "elem");
        ScopedCharPtr err;
        if (!csl_bridge_plutus_list_add(st->get(), elem->get(), &err.ptr)) {
          throw jsi::JSError(rt, err.ptr ? err.ptr : "PlutusList.add: Unknown CSL error");
        }
        return jsi::Value::undefined();
      }
    )
  );

  // Freeze the prototype, to prevent JS from changing methods accidentally
  auto ObjectCtor = rt.global().getPropertyAsObject(rt, "Object");
  if (ObjectCtor.isFunction(rt)) {
    auto freezeVal = ObjectCtor.getProperty(rt, "freeze");
    if (freezeVal.isObject() && freezeVal.asObject(rt).isFunction(rt)) {
      freezeVal.asObject(rt).asFunction(rt).call(rt, proto);
    }
  }

  s_PlutusList_proto_weak = jsi::WeakObject(rt, proto);
  return proto;
}

