static jsi::Object makeProposedProtocolParameterUpdatesExport(jsi::Runtime& rt) {
  jsi::Object ns(rt);

  // from_bytes
  ns.setProperty(rt, "from_bytes",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "from_bytes"), 1,
      [](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t count) -> jsi::Value {
        if (count < 1 || !args[0].isObject()) {
          throw jsi::JSError(rt, "ProposedProtocolParameterUpdates.from_bytes(bytes): expected Uint8Array");
        }
        auto bytes = parseUint8Array(rt, args[0].asObject(rt), "ProposedProtocolParameterUpdates.from_bytes", "bytes");
        return callCslProposedProtocolParameterUpdates(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_proposed_protocol_parameter_updates_from_bytes(bytes.data(), static_cast<size_t>(bytes.size()), out, err);
        }, "ProposedProtocolParameterUpdates.from_bytes");
      }
    )
  );

  // from_hex
  ns.setProperty(rt, "from_hex",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "from_hex"), 1,
      [](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t count) -> jsi::Value {
        if (count < 1 || !args[0].isString()) {
          throw jsi::JSError(rt, "ProposedProtocolParameterUpdates.from_hex(hex_str): expected string");
        }
        std::string hex_str = args[0].asString(rt).utf8(rt);
        return callCslProposedProtocolParameterUpdates(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_proposed_protocol_parameter_updates_from_hex(hex_str.c_str(), out, err);
        }, "ProposedProtocolParameterUpdates.from_hex");
      }
    )
  );

  // from_json
  ns.setProperty(rt, "from_json",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "from_json"), 1,
      [](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t count) -> jsi::Value {
        if (count < 1 || !args[0].isString()) {
          throw jsi::JSError(rt, "ProposedProtocolParameterUpdates.from_json(json): expected string");
        }
        std::string json = args[0].asString(rt).utf8(rt);
        return callCslProposedProtocolParameterUpdates(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_proposed_protocol_parameter_updates_from_json(json.c_str(), out, err);
        }, "ProposedProtocolParameterUpdates.from_json");
      }
    )
  );

  // new
  ns.setProperty(rt, "new",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "new"), 0,
      [](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t count) -> jsi::Value {
        return callCslProposedProtocolParameterUpdates(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_proposed_protocol_parameter_updates_new(out, err);
        }, "ProposedProtocolParameterUpdates.new");
      }
    )
  );

  auto ObjectCtor = rt.global().getPropertyAsObject(rt, "Object");
  if (ObjectCtor.isFunction(rt)) {
    auto freezeVal = ObjectCtor.getProperty(rt, "freeze");
    if (freezeVal.isObject() && freezeVal.asObject(rt).isFunction(rt)) {
      freezeVal.asObject(rt).asFunction(rt).call(rt, ns);
    }
  }

  return ns;
}

// ===================== ProtocolParamUpdate ========================
static std::optional<jsi::WeakObject> s_ProtocolParamUpdate_proto_weak;

static jsi::Object getOrCreateProtocolParamUpdateProto(jsi::Runtime& rt);

// ---------- Wrappers to create ProtocolParamUpdate and attach prototype --------------
static jsi::Object createProtocolParamUpdateRaw(jsi::Runtime& rt, const RPtr& ptr) {
  jsi::Object obj(rt);
  obj.setNativeState(rt, std::make_shared<ProtocolParamUpdateNativeState>(ptr));
  return obj;
}

static jsi::Object makeProtocolParamUpdateInstance(jsi::Runtime& rt, const RPtr& ptr) {
  jsi::Object obj = createProtocolParamUpdateRaw(rt, ptr);
  jsi::Object proto = getOrCreateProtocolParamUpdateProto(rt);
  setPrototype(rt, obj, proto);
  return obj;
}

static jsi::Object callCslProtocolParamUpdate(jsi::Runtime& rt, std::function<bool(RPtr*, CharPtr*)> fn, const char* location) {
  RPtr result{nullptr};
  ScopedCharPtr err;
  if (!fn(&result, &err.ptr)) {
    std::string errorMsg = err.ptr ? err.ptr : (std::string(location) + ": Unknown CSL error");
    throw jsi::JSError(rt, errorMsg);
  }
  return makeProtocolParamUpdateInstance(rt, result);
}

