static jsi::Object callCslPublicKeys(jsi::Runtime& rt, std::function<bool(RPtr*, CharPtr*)> fn, const char* location) {
  RPtr result{nullptr};
  ScopedCharPtr err;
  if (!fn(&result, &err.ptr)) {
    std::string errorMsg = err.ptr ? err.ptr : (std::string(location) + ": Unknown CSL error");
    throw jsi::JSError(rt, errorMsg);
  }
  return makePublicKeysInstance(rt, result);
}

static jsi::Object getOrCreatePublicKeysProto(jsi::Runtime& rt) {
  if (s_PublicKeys_proto_weak.has_value()) {
    auto locked = s_PublicKeys_proto_weak->lock(rt);
    if (locked.isObject()) {
      return locked.asObject(rt);
    }
  }

  jsi::Object proto(rt);

  // size(): number
  proto.setProperty(rt, "size",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "size"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisPublicKeysState(rt, thisVal);
        int64_t res{}; ScopedCharPtr err;
        if (!csl_bridge_public_keys_size(st->get(), &res, &err.ptr)) {
          throw jsi::JSError(rt, err.ptr ? err.ptr : "PublicKeys.size: Unknown CSL error");
        }
        return jsi::Value(static_cast<double>(res));
      }
    )
  );

  // get(): PublicKey
  proto.setProperty(rt, "get",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "get"), 1,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisPublicKeysState(rt, thisVal);
        if (count < 1 || !args[0].isNumber()) {
          throw jsi::JSError(rt, "PublicKeys.get(index): expected number");
        }
        auto index = static_cast<int64_t>(args[0].asNumber());
        RPtr result{nullptr};
        ScopedCharPtr err;
        if (!csl_bridge_public_keys_get(st->get(), index, &result, &err.ptr)) {
          if (!err.ptr) {
            return jsi::Value::null();
          }
          throw jsi::JSError(rt, err.ptr ? err.ptr : "PublicKeys.get: Unknown CSL error");
        }
        if (result._0 == nullptr) {
          return jsi::Value::null();
        }
        return jsi::Value(callCslPublicKey(rt, [&](RPtr* out, CharPtr* err) {
          *out = result;
          return true;
        }, "PublicKeys.get"));
      }
    )
  );

  // add(): void
  proto.setProperty(rt, "add",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "add"), 1,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisPublicKeysState(rt, thisVal);
        if (count < 1 || !args[0].isObject()) {
          throw jsi::JSError(rt, "PublicKeys.add(key): expected PublicKey");
        }
        auto key = getPublicKeyState(rt, args[0].asObject(rt), "key");
        ScopedCharPtr err;
        if (!csl_bridge_public_keys_add(st->get(), key->get(), &err.ptr)) {
          throw jsi::JSError(rt, err.ptr ? err.ptr : "PublicKeys.add: Unknown CSL error");
        }
        return jsi::Value::undefined();
      }
    )
  );

  // Freeze the prototype, to prevent JS from changing methods accidentally
  auto ObjectCtor = rt.global().getPropertyAsObject(rt, "Object");
  if (ObjectCtor.isFunction(rt)) {
    auto freezeVal = ObjectCtor.getProperty(rt, "freeze");
    if (freezeVal.isObject() && freezeVal.asObject(rt).isFunction(rt)) {
      freezeVal.asObject(rt).asFunction(rt).call(rt, proto);
    }
  }

  s_PublicKeys_proto_weak = jsi::WeakObject(rt, proto);
  return proto;
}

static jsi::Object makePublicKeysExport(jsi::Runtime& rt) {
  jsi::Object ns(rt);

  // new
  ns.setProperty(rt, "new",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "new"), 0,
      [](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t count) -> jsi::Value {
        return callCslPublicKeys(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_public_keys_new(out, err);
        }, "PublicKeys.new");
      }
    )
  );

  auto ObjectCtor = rt.global().getPropertyAsObject(rt, "Object");
  if (ObjectCtor.isFunction(rt)) {
    auto freezeVal = ObjectCtor.getProperty(rt, "freeze");
    if (freezeVal.isObject() && freezeVal.asObject(rt).isFunction(rt)) {
      freezeVal.asObject(rt).asFunction(rt).call(rt, ns);
    }
  }

  return ns;
}

