static std::optional<jsi::WeakObject> s_Redeemers_proto_weak;

static jsi::Object getOrCreateRedeemersProto(jsi::Runtime& rt);

// ---------- Wrappers to create Redeemers and attach prototype --------------
static jsi::Object createRedeemersRaw(jsi::Runtime& rt, const RPtr& ptr) {
  jsi::Object obj(rt);
  obj.setNativeState(rt, std::make_shared<RedeemersNativeState>(ptr));
  return obj;
}

static jsi::Object makeRedeemersInstance(jsi::Runtime& rt, const RPtr& ptr) {
  jsi::Object obj = createRedeemersRaw(rt, ptr);
  jsi::Object proto = getOrCreateRedeemersProto(rt);
  setPrototype(rt, obj, proto);
  return obj;
}

static jsi::Object callCslRedeemers(jsi::Runtime& rt, std::function<bool(RPtr*, CharPtr*)> fn, const char* location) {
  RPtr result{nullptr};
  ScopedCharPtr err;
  if (!fn(&result, &err.ptr)) {
    std::string errorMsg = err.ptr ? err.ptr : (std::string(location) + ": Unknown CSL error");
    throw jsi::JSError(rt, errorMsg);
  }
  return makeRedeemersInstance(rt, result);
}

static jsi::Object getOrCreateRedeemersProto(jsi::Runtime& rt) {
  if (s_Redeemers_proto_weak.has_value()) {
    auto locked = s_Redeemers_proto_weak->lock(rt);
    if (locked.isObject()) {
      return locked.asObject(rt);
    }
  }

  jsi::Object proto(rt);

  // to_bytes(): Uint8Array
  proto.setProperty(rt, "to_bytes",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "to_bytes"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisRedeemersState(rt, thisVal);
        return callCslArray(rt, [&](DataPtr* out, CharPtr* err) {
          return csl_bridge_redeemers_to_bytes(st->get(), out, err);
        }, "Redeemers.to_bytes");
      }
    )
  );

  // to_hex(): String
  proto.setProperty(rt, "to_hex",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "to_hex"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisRedeemersState(rt, thisVal);
        return callCslString(rt, [&](CharPtr* out, CharPtr* err) {
          return csl_bridge_redeemers_to_hex(st->get(), out, err);
        }, "Redeemers.to_hex");
      }
    )
  );

  // to_json(): String
  proto.setProperty(rt, "to_json",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "to_json"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisRedeemersState(rt, thisVal);
        return callCslString(rt, [&](CharPtr* out, CharPtr* err) {
          return csl_bridge_redeemers_to_json(st->get(), out, err);
        }, "Redeemers.to_json");
      }
    )
  );

  // len(): number
  proto.setProperty(rt, "len",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "len"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisRedeemersState(rt, thisVal);
        int64_t res{}; ScopedCharPtr err;
        if (!csl_bridge_redeemers_len(st->get(), &res, &err.ptr)) {
          throw jsi::JSError(rt, err.ptr ? err.ptr : "Redeemers.len: Unknown CSL error");
        }
        return jsi::Value(static_cast<double>(res));
      }
    )
  );

  // get(): Redeemer
  proto.setProperty(rt, "get",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "get"), 1,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisRedeemersState(rt, thisVal);
        if (count < 1 || !args[0].isNumber()) {
          throw jsi::JSError(rt, "Redeemers.get(index): expected number");
        }
        auto index = static_cast<int64_t>(args[0].asNumber());
        RPtr result{nullptr};
        ScopedCharPtr err;
        if (!csl_bridge_redeemers_get(st->get(), index, &result, &err.ptr)) {
          if (!err.ptr) {
            return jsi::Value::null();
          }
          throw jsi::JSError(rt, err.ptr ? err.ptr : "Redeemers.get: Unknown CSL error");
        }
        if (result._0 == nullptr) {
          return jsi::Value::null();
        }
        return jsi::Value(callCslRedeemer(rt, [&](RPtr* out, CharPtr* err) {
          *out = result;
          return true;
        }, "Redeemers.get"));
      }
    )
  );

  // add(): void
  proto.setProperty(rt, "add",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "add"), 1,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisRedeemersState(rt, thisVal);
        if (count < 1 || !args[0].isObject()) {
          throw jsi::JSError(rt, "Redeemers.add(elem): expected Redeemer");
        }
        auto elem = getRedeemerState(rt, args[0].asObject(rt), "elem");
        ScopedCharPtr err;
        if (!csl_bridge_redeemers_add(st->get(), elem->get(), &err.ptr)) {
          throw jsi::JSError(rt, err.ptr ? err.ptr : "Redeemers.add: Unknown CSL error");
        }
        return jsi::Value::undefined();
      }
    )
  );

  // get_container_type(): CborContainerType
  proto.setProperty(rt, "get_container_type",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "get_container_type"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisRedeemersState(rt, thisVal);
        int32_t res{}; ScopedCharPtr err;
        if (!csl_bridge_redeemers_get_container_type(st->get(), &res, &err.ptr)) {
          throw jsi::JSError(rt, err.ptr ? err.ptr : "Redeemers.get_container_type: Unknown CSL error");
        }
        return jsi::Value(static_cast<double>(res));
      }
    )
  );

  // total_ex_units(): ExUnits
  proto.setProperty(rt, "total_ex_units",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "total_ex_units"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisRedeemersState(rt, thisVal);
        return callCslExUnits(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_redeemers_total_ex_units(st->get(), out, err);
        }, "Redeemers.total_ex_units");
      }
    )
  );

  // Freeze the prototype, to prevent JS from changing methods accidentally
  auto ObjectCtor = rt.global().getPropertyAsObject(rt, "Object");
  if (ObjectCtor.isFunction(rt)) {
    auto freezeVal = ObjectCtor.getProperty(rt, "freeze");
    if (freezeVal.isObject() && freezeVal.asObject(rt).isFunction(rt)) {
      freezeVal.asObject(rt).asFunction(rt).call(rt, proto);
    }
  }

  s_Redeemers_proto_weak = jsi::WeakObject(rt, proto);
  return proto;
}

