static jsi::Object createRelayRaw(jsi::Runtime& rt, const RPtr& ptr) {
  jsi::Object obj(rt);
  obj.setNativeState(rt, std::make_shared<RelayNativeState>(ptr));
  return obj;
}

static jsi::Object makeRelayInstance(jsi::Runtime& rt, const RPtr& ptr) {
  jsi::Object obj = createRelayRaw(rt, ptr);
  jsi::Object proto = getOrCreateRelayProto(rt);
  setPrototype(rt, obj, proto);
  return obj;
}

static jsi::Object callCslRelay(jsi::Runtime& rt, std::function<bool(RPtr*, CharPtr*)> fn, const char* location) {
  RPtr result{nullptr};
  ScopedCharPtr err;
  if (!fn(&result, &err.ptr)) {
    std::string errorMsg = err.ptr ? err.ptr : (std::string(location) + ": Unknown CSL error");
    throw jsi::JSError(rt, errorMsg);
  }
  return makeRelayInstance(rt, result);
}

static jsi::Object getOrCreateRelayProto(jsi::Runtime& rt) {
  if (s_Relay_proto_weak.has_value()) {
    auto locked = s_Relay_proto_weak->lock(rt);
    if (locked.isObject()) {
      return locked.asObject(rt);
    }
  }

  jsi::Object proto(rt);

  // to_bytes(): Uint8Array
  proto.setProperty(rt, "to_bytes",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "to_bytes"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisRelayState(rt, thisVal);
        return callCslArray(rt, [&](DataPtr* out, CharPtr* err) {
          return csl_bridge_relay_to_bytes(st->get(), out, err);
        }, "Relay.to_bytes");
      }
    )
  );

  // to_hex(): String
  proto.setProperty(rt, "to_hex",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "to_hex"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisRelayState(rt, thisVal);
        return callCslString(rt, [&](CharPtr* out, CharPtr* err) {
          return csl_bridge_relay_to_hex(st->get(), out, err);
        }, "Relay.to_hex");
      }
    )
  );

  // to_json(): String
  proto.setProperty(rt, "to_json",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "to_json"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisRelayState(rt, thisVal);
        return callCslString(rt, [&](CharPtr* out, CharPtr* err) {
          return csl_bridge_relay_to_json(st->get(), out, err);
        }, "Relay.to_json");
      }
    )
  );

  // kind(): RelayKind
  proto.setProperty(rt, "kind",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "kind"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisRelayState(rt, thisVal);
        int32_t res{}; ScopedCharPtr err;
        if (!csl_bridge_relay_kind(st->get(), &res, &err.ptr)) {
          throw jsi::JSError(rt, err.ptr ? err.ptr : "Relay.kind: Unknown CSL error");
        }
        return jsi::Value(static_cast<double>(res));
      }
    )
  );

  // as_single_host_addr(): SingleHostAddr
  proto.setProperty(rt, "as_single_host_addr",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "as_single_host_addr"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisRelayState(rt, thisVal);
        return callCslSingleHostAddr(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_relay_as_single_host_addr(st->get(), out, err);
        }, "Relay.as_single_host_addr");
      }
    )
  );

  // as_single_host_name(): SingleHostName
  proto.setProperty(rt, "as_single_host_name",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "as_single_host_name"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisRelayState(rt, thisVal);
        return callCslSingleHostName(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_relay_as_single_host_name(st->get(), out, err);
        }, "Relay.as_single_host_name");
      }
    )
  );

  // as_multi_host_name(): MultiHostName
  proto.setProperty(rt, "as_multi_host_name",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "as_multi_host_name"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisRelayState(rt, thisVal);
        return callCslMultiHostName(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_relay_as_multi_host_name(st->get(), out, err);
        }, "Relay.as_multi_host_name");
      }
    )
  );

  // Freeze the prototype, to prevent JS from changing methods accidentally
  auto ObjectCtor = rt.global().getPropertyAsObject(rt, "Object");
  if (ObjectCtor.isFunction(rt)) {
    auto freezeVal = ObjectCtor.getProperty(rt, "freeze");
    if (freezeVal.isObject() && freezeVal.asObject(rt).isFunction(rt)) {
      freezeVal.asObject(rt).asFunction(rt).call(rt, proto);
    }
  }

  s_Relay_proto_weak = jsi::WeakObject(rt, proto);
  return proto;
}

static jsi::Object makeRelayExport(jsi::Runtime& rt) {
  jsi::Object ns(rt);

  // from_bytes
  ns.setProperty(rt, "from_bytes",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "from_bytes"), 1,
      [](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t count) -> jsi::Value {
        if (count < 1 || !args[0].isObject()) {
          throw jsi::JSError(rt, "Relay.from_bytes(bytes): expected Uint8Array");
        }
        auto bytes = parseUint8Array(rt, args[0].asObject(rt), "Relay.from_bytes", "bytes");
        return callCslRelay(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_relay_from_bytes(bytes.data(), static_cast<size_t>(bytes.size()), out, err);
        }, "Relay.from_bytes");
      }
    )
  );

  // from_hex
  ns.setProperty(rt, "from_hex",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "from_hex"), 1,
      [](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t count) -> jsi::Value {
        if (count < 1 || !args[0].isString()) {
          throw jsi::JSError(rt, "Relay.from_hex(hex_str): expected string");
        }
        std::string hex_str = args[0].asString(rt).utf8(rt);
        return callCslRelay(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_relay_from_hex(hex_str.c_str(), out, err);
        }, "Relay.from_hex");
      }
    )
  );

  // from_json
  ns.setProperty(rt, "from_json",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "from_json"), 1,
      [](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t count) -> jsi::Value {
        if (count < 1 || !args[0].isString()) {
          throw jsi::JSError(rt, "Relay.from_json(json): expected string");
        }
        std::string json = args[0].asString(rt).utf8(rt);
        return callCslRelay(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_relay_from_json(json.c_str(), out, err);
        }, "Relay.from_json");
      }
    )
  );

  // new_single_host_addr
  ns.setProperty(rt, "new_single_host_addr",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "new_single_host_addr"), 1,
      [](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t count) -> jsi::Value {
        if (count < 1 || !args[0].isObject()) {
          throw jsi::JSError(rt, "Relay.new_single_host_addr(single_host_addr): expected SingleHostAddr");
        }
        auto single_host_addr = getSingleHostAddrState(rt, args[0].asObject(rt), "single_host_addr");
        return callCslRelay(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_relay_new_single_host_addr(single_host_addr->get(), out, err);
        }, "Relay.new_single_host_addr");
      }
    )
  );

  // new_single_host_name
  ns.setProperty(rt, "new_single_host_name",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "new_single_host_name"), 1,
      [](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t count) -> jsi::Value {
        if (count < 1 || !args[0].isObject()) {
          throw jsi::JSError(rt, "Relay.new_single_host_name(single_host_name): expected SingleHostName");
        }
        auto single_host_name = getSingleHostNameState(rt, args[0].asObject(rt), "single_host_name");
        return callCslRelay(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_relay_new_single_host_name(single_host_name->get(), out, err);
        }, "Relay.new_single_host_name");
      }
    )
  );

  // new_multi_host_name
  ns.setProperty(rt, "new_multi_host_name",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "new_multi_host_name"), 1,
      [](jsi::Runtime& rt, const jsi::Value&, const jsi::Value* args, size_t count) -> jsi::Value {
        if (count < 1 || !args[0].isObject()) {
          throw jsi::JSError(rt, "Relay.new_multi_host_name(multi_host_name): expected MultiHostName");
        }
        auto multi_host_name = getMultiHostNameState(rt, args[0].asObject(rt), "multi_host_name");
        return callCslRelay(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_relay_new_multi_host_name(multi_host_name->get(), out, err);
        }, "Relay.new_multi_host_name");
      }
    )
  );

  auto ObjectCtor = rt.global().getPropertyAsObject(rt, "Object");
  if (ObjectCtor.isFunction(rt)) {
    auto freezeVal = ObjectCtor.getProperty(rt, "freeze");
    if (freezeVal.isObject() && freezeVal.asObject(rt).isFunction(rt)) {
      freezeVal.asObject(rt).asFunction(rt).call(rt, ns);
    }
  }

  return ns;
}

// ===================== Relays ========================
static std::optional<jsi::WeakObject> s_Relays_proto_weak;

static jsi::Object getOrCreateRelaysProto(jsi::Runtime& rt);

// ---------- Wrappers to create Relays and attach prototype --------------
static jsi::Object createRelaysRaw(jsi::Runtime& rt, const RPtr& ptr) {
  jsi::Object obj(rt);
  obj.setNativeState(rt, std::make_shared<RelaysNativeState>(ptr));
  return obj;
}

static jsi::Object makeRelaysInstance(jsi::Runtime& rt, const RPtr& ptr) {
  jsi::Object obj = createRelaysRaw(rt, ptr);
  jsi::Object proto = getOrCreateRelaysProto(rt);
  setPrototype(rt, obj, proto);
  return obj;
}

static jsi::Object callCslRelays(jsi::Runtime& rt, std::function<bool(RPtr*, CharPtr*)> fn, const char* location) {
  RPtr result{nullptr};
  ScopedCharPtr err;
  if (!fn(&result, &err.ptr)) {
    std::string errorMsg = err.ptr ? err.ptr : (std::string(location) + ": Unknown CSL error");
    throw jsi::JSError(rt, errorMsg);
  }
  return makeRelaysInstance(rt, result);
}

static jsi::Object getOrCreateRelaysProto(jsi::Runtime& rt) {
  if (s_Relays_proto_weak.has_value()) {
    auto locked = s_Relays_proto_weak->lock(rt);
    if (locked.isObject()) {
      return locked.asObject(rt);
    }
  }

  jsi::Object proto(rt);

  // to_bytes(): Uint8Array
  proto.setProperty(rt, "to_bytes",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "to_bytes"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisRelaysState(rt, thisVal);
        return callCslArray(rt, [&](DataPtr* out, CharPtr* err) {
          return csl_bridge_relays_to_bytes(st->get(), out, err);
        }, "Relays.to_bytes");
      }
    )
  );

  // to_hex(): String
  proto.setProperty(rt, "to_hex",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "to_hex"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisRelaysState(rt, thisVal);
        return callCslString(rt, [&](CharPtr* out, CharPtr* err) {
          return csl_bridge_relays_to_hex(st->get(), out, err);
        }, "Relays.to_hex");
      }
    )
  );

  // to_json(): String
  proto.setProperty(rt, "to_json",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "to_json"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisRelaysState(rt, thisVal);
        return callCslString(rt, [&](CharPtr* out, CharPtr* err) {
          return csl_bridge_relays_to_json(st->get(), out, err);
        }, "Relays.to_json");
      }
    )
  );

  // len(): number
  proto.setProperty(rt, "len",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "len"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisRelaysState(rt, thisVal);
        int64_t res{}; ScopedCharPtr err;
        if (!csl_bridge_relays_len(st->get(), &res, &err.ptr)) {
          throw jsi::JSError(rt, err.ptr ? err.ptr : "Relays.len: Unknown CSL error");
        }
        return jsi::Value(static_cast<double>(res));
      }
    )
  );

  // get(): Relay
  proto.setProperty(rt, "get",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "get"), 1,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisRelaysState(rt, thisVal);
        if (count < 1 || !args[0].isNumber()) {
          throw jsi::JSError(rt, "Relays.get(index): expected number");
        }
        auto index = static_cast<int64_t>(args[0].asNumber());
        RPtr result{nullptr};
        ScopedCharPtr err;
        if (!csl_bridge_relays_get(st->get(), index, &result, &err.ptr)) {
          if (!err.ptr) {
            return jsi::Value::null();
          }
          throw jsi::JSError(rt, err.ptr ? err.ptr : "Relays.get: Unknown CSL error");
        }
        if (result._0 == nullptr) {
          return jsi::Value::null();
        }
        return jsi::Value(callCslRelay(rt, [&](RPtr* out, CharPtr* err) {
          *out = result;
          return true;
        }, "Relays.get"));
      }
    )
  );

  // add(): void
  proto.setProperty(rt, "add",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "add"), 1,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisRelaysState(rt, thisVal);
        if (count < 1 || !args[0].isObject()) {
          throw jsi::JSError(rt, "Relays.add(elem): expected Relay");
        }
        auto elem = getRelayState(rt, args[0].asObject(rt), "elem");
        ScopedCharPtr err;
        if (!csl_bridge_relays_add(st->get(), elem->get(), &err.ptr)) {
          throw jsi::JSError(rt, err.ptr ? err.ptr : "Relays.add: Unknown CSL error");
        }
        return jsi::Value::undefined();
      }
    )
  );

  // Freeze the prototype, to prevent JS from changing methods accidentally
  auto ObjectCtor = rt.global().getPropertyAsObject(rt, "Object");
  if (ObjectCtor.isFunction(rt)) {
    auto freezeVal = ObjectCtor.getProperty(rt, "freeze");
    if (freezeVal.isObject() && freezeVal.asObject(rt).isFunction(rt)) {
      freezeVal.asObject(rt).asFunction(rt).call(rt, proto);
    }
  }

  s_Relays_proto_weak = jsi::WeakObject(rt, proto);
  return proto;
}

