// ===================== Value ========================
static std::optional<jsi::WeakObject> s_Value_proto_weak;

static jsi::Object getOrCreateValueProto(jsi::Runtime& rt);

// ---------- Wrappers to create Value and attach prototype --------------
static jsi::Object createValueRaw(jsi::Runtime& rt, const RPtr& ptr) {
  jsi::Object obj(rt);
  obj.setNativeState(rt, std::make_shared<ValueNativeState>(ptr));
  return obj;
}

static jsi::Object makeValueInstance(jsi::Runtime& rt, const RPtr& ptr) {
  jsi::Object obj = createValueRaw(rt, ptr);
  jsi::Object proto = getOrCreateValueProto(rt);
  setPrototype(rt, obj, proto);
  return obj;
}

static jsi::Object callCslValue(jsi::Runtime& rt, std::function<bool(RPtr*, CharPtr*)> fn, const char* location) {
  RPtr result{nullptr};
  ScopedCharPtr err;
  if (!fn(&result, &err.ptr)) {
    std::string errorMsg = err.ptr ? err.ptr : (std::string(location) + ": Unknown CSL error");
    throw jsi::JSError(rt, errorMsg);
  }
  return makeValueInstance(rt, result);
}

static jsi::Object getOrCreateValueProto(jsi::Runtime& rt) {
  if (s_Value_proto_weak.has_value()) {
    auto locked = s_Value_proto_weak->lock(rt);
    if (locked.isObject()) {
      return locked.asObject(rt);
    }
  }

  jsi::Object proto(rt);

  // to_bytes(): Uint8Array
  proto.setProperty(rt, "to_bytes",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "to_bytes"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisValueState(rt, thisVal);
        return callCslArray(rt, [&](DataPtr* out, CharPtr* err) {
          return csl_bridge_value_to_bytes(st->get(), out, err);
        }, "Value.to_bytes");
      }
    )
  );

  // to_hex(): String
  proto.setProperty(rt, "to_hex",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "to_hex"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisValueState(rt, thisVal);
        return callCslString(rt, [&](CharPtr* out, CharPtr* err) {
          return csl_bridge_value_to_hex(st->get(), out, err);
        }, "Value.to_hex");
      }
    )
  );

  // to_json(): String
  proto.setProperty(rt, "to_json",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "to_json"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisValueState(rt, thisVal);
        return callCslString(rt, [&](CharPtr* out, CharPtr* err) {
          return csl_bridge_value_to_json(st->get(), out, err);
        }, "Value.to_json");
      }
    )
  );

  // is_zero(): boolean
  proto.setProperty(rt, "is_zero",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "is_zero"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisValueState(rt, thisVal);
        bool res = false; ScopedCharPtr err;
        if (!csl_bridge_value_is_zero(st->get(), &res, &err.ptr)) {
          throw jsi::JSError(rt, err.ptr ? err.ptr : "Value.is_zero: Unknown CSL error");
        }
        return jsi::Value(res);
      }
    )
  );

  // coin(): BigNum
  proto.setProperty(rt, "coin",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "coin"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisValueState(rt, thisVal);
        return callCslBigNum(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_value_coin(st->get(), out, err);
        }, "Value.coin");
      }
    )
  );

  // set_coin(): void
  proto.setProperty(rt, "set_coin",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "set_coin"), 1,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisValueState(rt, thisVal);
        if (count < 1 || !args[0].isObject()) {
          throw jsi::JSError(rt, "Value.set_coin(coin): expected BigNum");
        }
        auto coin = getBigNumState(rt, args[0].asObject(rt), "coin");
        ScopedCharPtr err;
        if (!csl_bridge_value_set_coin(st->get(), coin->get(), &err.ptr)) {
          throw jsi::JSError(rt, err.ptr ? err.ptr : "Value.set_coin: Unknown CSL error");
        }
        return jsi::Value::undefined();
      }
    )
  );

  // multiasset(): MultiAsset
  proto.setProperty(rt, "multiasset",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "multiasset"), 0,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisValueState(rt, thisVal);
        return callCslMultiAsset(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_value_multiasset(st->get(), out, err);
        }, "Value.multiasset");
      }
    )
  );

  // set_multiasset(): void
  proto.setProperty(rt, "set_multiasset",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "set_multiasset"), 1,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisValueState(rt, thisVal);
        if (count < 1 || !args[0].isObject()) {
          throw jsi::JSError(rt, "Value.set_multiasset(multiasset): expected MultiAsset");
        }
        auto multiasset = getMultiAssetState(rt, args[0].asObject(rt), "multiasset");
        ScopedCharPtr err;
        if (!csl_bridge_value_set_multiasset(st->get(), multiasset->get(), &err.ptr)) {
          throw jsi::JSError(rt, err.ptr ? err.ptr : "Value.set_multiasset: Unknown CSL error");
        }
        return jsi::Value::undefined();
      }
    )
  );

  // checked_add(): Value
  proto.setProperty(rt, "checked_add",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "checked_add"), 1,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisValueState(rt, thisVal);
        if (count < 1 || !args[0].isObject()) {
          throw jsi::JSError(rt, "Value.checked_add(rhs): expected Value");
        }
        auto rhs = getValueState(rt, args[0].asObject(rt), "rhs");
        return callCslValue(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_value_checked_add(st->get(), rhs->get(), out, err);
        }, "Value.checked_add");
      }
    )
  );

  // checked_sub(): Value
  proto.setProperty(rt, "checked_sub",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "checked_sub"), 1,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisValueState(rt, thisVal);
        if (count < 1 || !args[0].isObject()) {
          throw jsi::JSError(rt, "Value.checked_sub(rhs_value): expected Value");
        }
        auto rhs_value = getValueState(rt, args[0].asObject(rt), "rhs_value");
        return callCslValue(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_value_checked_sub(st->get(), rhs_value->get(), out, err);
        }, "Value.checked_sub");
      }
    )
  );

  // clamped_sub(): Value
  proto.setProperty(rt, "clamped_sub",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "clamped_sub"), 1,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisValueState(rt, thisVal);
        if (count < 1 || !args[0].isObject()) {
          throw jsi::JSError(rt, "Value.clamped_sub(rhs_value): expected Value");
        }
        auto rhs_value = getValueState(rt, args[0].asObject(rt), "rhs_value");
        return callCslValue(rt, [&](RPtr* out, CharPtr* err) {
          return csl_bridge_value_clamped_sub(st->get(), rhs_value->get(), out, err);
        }, "Value.clamped_sub");
      }
    )
  );

  // compare(): number
  proto.setProperty(rt, "compare",
    jsi::Function::createFromHostFunction(rt, jsi::PropNameID::forAscii(rt, "compare"), 1,
      [](jsi::Runtime& rt, const jsi::Value& thisVal, const jsi::Value* args, size_t count) -> jsi::Value {
        auto st = getThisValueState(rt, thisVal);
        if (count < 1 || !args[0].isObject()) {
          throw jsi::JSError(rt, "Value.compare(rhs_value): expected Value");
        }
        auto rhs_value = getValueState(rt, args[0].asObject(rt), "rhs_value");
        int64_t res{}; ScopedCharPtr err;
        if (!csl_bridge_value_compare(st->get(), rhs_value->get(), &res, &err.ptr)) {
          throw jsi::JSError(rt, err.ptr ? err.ptr : "Value.compare: Unknown CSL error");
        }
        return jsi::Value(static_cast<double>(res));
      }
    )
  );

  // Freeze the prototype, to prevent JS from changing methods accidentally
  auto ObjectCtor = rt.global().getPropertyAsObject(rt, "Object");
  if (ObjectCtor.isFunction(rt)) {
    auto freezeVal = ObjectCtor.getProperty(rt, "freeze");
    if (freezeVal.isObject() && freezeVal.asObject(rt).isFunction(rt)) {
      freezeVal.asObject(rt).asFunction(rt).call(rt, proto);
    }
  }

  s_Value_proto_weak = jsi::WeakObject(rt, proto);
  return proto;
}

